<script>
function showError(message){document.getElementById('tool-error-text').textContent=message;document.getElementById('tool-error').style.display='flex';document.getElementById('tool-result').classList.remove('show');}
function clearError(){document.getElementById('tool-error').style.display='none';}
function runTool(){const numero=parseFloat(document.getElementById('raiz-numero').value);clearError();if(isNaN(numero)||numero<0){showError('Informe um número válido maior ou igual a zero.');return;}const raiz=Math.sqrt(numero);document.getElementById('raiz-valor').textContent=fmtNum(raiz,6);document.getElementById('raiz-verificacao').textContent=fmtNum(raiz*raiz,6);document.getElementById('tool-detail').textContent='A verificação mostra o valor da raiz multiplicado por ele mesmo.';showResult('tool-result');}function clearTool(){document.getElementById('raiz-numero').value='';['raiz-valor','raiz-verificacao'].forEach(id=>document.getElementById(id).textContent='-');document.getElementById('tool-detail').textContent='';document.getElementById('tool-result').classList.remove('show');clearError();}function copyTool(button){if(!document.getElementById('tool-result').classList.contains('show')){showError('Calcule a raiz antes de copiar o resultado.');return;}copyToClipboard('Raiz quadrada: '+document.getElementById('raiz-valor').textContent,button);}
</script>
